using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 3, 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.AddItem("SKU-001", 3, 10.00m);

        Assert.AreEqual(50.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.AddItem(sku!, 1, 10.00m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRangeException(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU-001", quantity, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU-001", 1, -5.00m));
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("DOES-NOT-EXIST"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveItem_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem(sku!));
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentItems()
    {
        _cart.AddItem("SKU-001", 2, 15.00m);
        _cart.AddItem("SKU-002", 1, 7.50m);
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    [DataRow("SAVE10", 90.00)]
    [DataRow("SAVE20", 80.00)]
    [DataRow("HALF", 50.00)]
    public void ApplyCoupon_ValidCode_AppliesDiscount(string code, double expected)
    {
        _cart.AddItem("SKU-001", 1, 100.00m);

        _cart.ApplyCoupon(code);

        Assert.AreEqual((decimal)expected, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_AppliesDiscount()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);

        _cart.ApplyCoupon("save10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_NullOrEmpty_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedAfterAddingItems_DiscountsEntireCart()
    {
        _cart.AddItem("SKU-001", 2, 25.00m);
        _cart.AddItem("SKU-002", 1, 50.00m);

        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }
}

